class ProductService {

    private static final Logger log = LoggerFactory.getLogger(ProductService.class);
    private static final String PRODUCTS_INDEX = "products";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
        // Ensure indices are created on startup
        createProductIndex();
    }

    public void createProductIndex() {
        try {
            GetIndexRequest request = new GetIndexRequest(PRODUCTS_INDEX);
            boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);

            if (!exists) {
                log.info("Creating index: {}", PRODUCTS_INDEX);
                CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCTS_INDEX);
                createIndexRequest.settings(Settings.builder()
                        .put("index.number_of_shards", 1)
                        .put("index.number_of_replicas", 0)
                );
                createIndexRequest.mapping(
                        "{\n" +
                                "  \"properties\": {\n" +
                                "    \"id\": { \"type\": \"keyword\" },\n" +
                                "    \"name\": { \"type\": \"text\", \"analyzer\": \"standard\" },\n" +
                                "    \"description\": { \"type\": \"text\", \"analyzer\": \"standard\" },\n" +
                                "    \"price\": { \"type\": \"double\" },\n" +
                                "    \"category\": { \"type\": \"keyword\" },\n" +
                                "    \"brand\": { \"type\": \"keyword\" },\n" +
                                "    \"sku\": { \"type\": \"keyword\" },\n" +
                                "    \"imageUrl\": { \"type\": \"keyword\", \"index\": false },\n" +
                                "    \"available\": { \"type\": \"boolean\" }\n" +
                                "  }\n" +
                                "}",
                        XContentType.JSON
                );
                client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
                log.info("Index {} created successfully.", PRODUCTS_INDEX);
            } else {
                log.info("Index {} already exists.", PRODUCTS_INDEX);
            }
        } catch (IOException e) {
            log.error("Error creating or checking index {}: {}", PRODUCTS_INDEX, e.getMessage());
        }
    }

    public IndexResponse indexProduct(Product product) throws IOException {
        if (product.getId() == null) {
            product.setId(UUID.randomUUID().toString()); // Generate ID if not provided
        }
        IndexRequest request = new IndexRequest(PRODUCTS_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON);
        return client.index(request, RequestOptions.DEFAULT);
    }

    public SearchResult searchProducts(String query, List<String> categories, List<String> brands, Double minPrice, Double maxPrice, int page, int size) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCTS_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();

        // Pagination
        searchSourceBuilder.from(page * size);
        searchSourceBuilder.size(size);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search query
        if (query != null && !query.trim().isEmpty()) {
            MultiMatchQueryBuilder multiMatchQuery = QueryBuilders.multiMatchQuery(query, "name^3", "description^1");
            boolQuery.must(multiMatchQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery()); // If no query, return all
        }

        // Faceted navigation filters
        if (categories != null && !categories.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", categories));
        }
        if (brands != null && !brands.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", brands));
        }
        if (minPrice != null || maxPrice != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (minPrice != null) rangeQuery.gte(minPrice);
            if (maxPrice != null) rangeQuery.lte(maxPrice);
            boolQuery.filter(rangeQuery);
        }

        searchSourceBuilder.query(boolQuery);

        // Aggregations for faceted navigation
        AggregationBuilder categoryAggregation = AggregationBuilders.terms("category_agg").field("category.keyword").size(100);
        searchSourceBuilder.aggregation(categoryAggregation);

        AggregationBuilder brandAggregation = AggregationBuilders.terms("brand_agg").field("brand.keyword").size(100);
        searchSourceBuilder.aggregation(brandAggregation);

        searchRequest.source(searchSourceBuilder);

        SearchResponse searchResponse = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            products.add(objectMapper.readValue(hit.getSourceAsString(), Product.class));
        }

        Map<String, Map<String, Long>> facets = new HashMap<>();
        if (searchResponse.getAggregations() != null) {
            Terms categoryTerms = searchResponse.getAggregations().get("category_agg");
            if (categoryTerms != null) {
                Map<String, Long> categoryFacet = categoryTerms.getBuckets().stream()
                        .collect(Collectors.toMap(Terms.Bucket::getKeyAsString, Terms.Bucket::getDocCount));
                facets.put("category", categoryFacet);
            }

            Terms brandTerms = searchResponse.getAggregations().get("brand_agg");
            if (brandTerms != null) {
                Map<String, Long> brandFacet = brandTerms.getBuckets().stream()
                        .collect(Collectors.toMap(Terms.Bucket::getKeyAsString, Terms.Bucket::getDocCount));
                facets.put("brand", brandFacet);
            }
        }

        long totalHits = searchResponse.getHits().getTotalHits().value;

        return new SearchResult(products, facets, totalHits, page, size);
    }
}

class SearchQueryLogService {

    private static final Logger log = LoggerFactory.getLogger(SearchQueryLogService.class);
    private static final String SEARCH_QUERIES_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public SearchQueryLogService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
        createSearchQueryLogIndex();
    }

    public void createSearchQueryLogIndex() {
        try {
            GetIndexRequest request = new GetIndexRequest(SEARCH_QUERIES_INDEX);
            boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);

            if (!exists) {
                log.info("Creating index: {}", SEARCH_QUERIES_INDEX);
                CreateIndexRequest createIndexRequest = new CreateIndexRequest(SEARCH_QUERIES_INDEX);
                createIndexRequest.settings(Settings.builder()
                        .put("index.number_of_shards", 1)
                        .put("index.number_of_replicas", 0)
                );
                createIndexRequest.mapping(
                        "{\n" +
                                "  \"properties\": {\n" +
                                "    \"id\": { \"type\": \"keyword\" },\n" +
                                "    \"queryText\": { \"type\": \"text\" },\n" +
                                "    \"timestamp\": { \"type\": \"date\" },\n" +
                                "    \"userId\": { \"type\": \"keyword\" }\n" +
                                "  }\n" +
                                "}",
                        XContentType.JSON
                );
                client.indices().create(createIndexRequest, RequestOptions.DEFAULT);
                log.info("Index {} created successfully.", SEARCH_QUERIES_INDEX);
            } else {
                log.info("Index {} already exists.", SEARCH_QUERIES_INDEX);
            }
        } catch (IOException e) {
            log.error("Error creating or checking index {}: {}", SEARCH_QUERIES_INDEX, e.getMessage());
        }
    }

    public IndexResponse logQuery(String queryText, String userId) throws IOException {
        if (queryText == null || queryText.trim().isEmpty()) {
            return null; // Don't log empty queries
        }
        SearchQueryLog logEntry = new SearchQueryLog(UUID.randomUUID().toString(), queryText, LocalDateTime.now(), userId);
        IndexRequest request = new IndexRequest(SEARCH_QUERIES_INDEX)
                .id(logEntry.getId())
                .source(objectMapper.writeValueAsString(logEntry), XContentType.JSON);
        return client.index(request, RequestOptions.DEFAULT);
    }
}

